import React, { useState, useEffect } from 'react';
import JSZip from 'jszip';
import './App.css';

function App() {
  const [curtainOpen, setCurtainOpen] = useState(false);
  const [logoFade, setLogoFade] = useState(false);
  const [activeTab, setActiveTab] = useState('home');
  const [zipImages, setZipImages] = useState([]);
  const [isProcessingZip, setIsProcessingZip] = useState(false);

  useEffect(() => {
    const timer1 = setTimeout(() => setLogoFade(true), 1500);
    const timer2 = setTimeout(() => setCurtainOpen(true), 2200);

    return () => {
      clearTimeout(timer1);
      clearTimeout(timer2);
    };
  }, []);

  // Handle uploading and unzipping user's actual ZIP archive
  const handleZipUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    setIsProcessingZip(true);
    setZipImages([]);

    try {
      const zip = new JSZip();
      const zipContent = await zip.loadAsync(file);
      const imagePromises = [];

      zipContent.forEach((relativePath, zipEntry) => {
        if (!zipEntry.dir && /\.(png|jpe?g|svg|webp|gif)$/i.test(zipEntry.name)) {
          const promise = zipEntry.async('blob').then((blob) => ({
            name: zipEntry.name,
            url: URL.createObjectURL(blob),
          }));
          imagePromises.push(promise);
        }
      });

      const extractedImages = await Promise.all(imagePromises);
      setZipImages(extractedImages);
    } catch (err) {
      alert('Error reading ZIP file. Please upload a valid .zip archive.');
    } finally {
      setIsProcessingZip(false);
    }
  };

  return (
    <div className="app-container">
      {/* 1. CURTAIN INTRO ANIMATION WITH YOUR LOGO */}
      <div className="curtain-container">
        <div className={`curtain-panel left ${curtainOpen ? 'open' : ''}`} />
        <div className={`curtain-panel right ${curtainOpen ? 'open' : ''}`} />
        <div className={`curtain-logo-wrapper ${logoFade ? 'fade-out' : ''}`}>
          <img src={"C:\Users\Rubhasree\Documents\WhatsApp Image 2026-07-20 at 9.49.24 PM.jpeg"} alt="Jillu Curtains Logo" style={{ width: '180px', marginBottom: '15px' }} />
          <p style={{ color: '#d4af37', letterSpacing: '2px', fontWeight: 'bold' }}>WINDOW DRESSING SOLUTIONS</p>
        </div>
      </div>

      {/* 2. HEADER NAVBAR */}
      <header className="navbar">
        <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
          <img src={logo} alt="Logo" style={{ height: '40px' }} />
          <span className="gold-text" style={{ fontSize: '1.2rem', fontWeight: 'bold' }}>JILLU CURTAINS</span>
        </div>
        <ul className="nav-links">
          {['home', 'about', 'services', 'gallery', 'contact'].map((tab) => (
            <li key={tab} className={activeTab === tab ? 'active' : ''} onClick={() => setActiveTab(tab)}>
              {tab.toUpperCase()}
            </li>
          ))}
        </ul>
      </header>

      {/* 3. DYNAMIC CONTENT */}
      <main className="page-wrapper">
        {activeTab === 'home' && <HomePage setActiveTab={setActiveTab} />}
        {activeTab === 'about' && <AboutPage />}
        {activeTab === 'services' && <ServicesPage />}
        {activeTab === 'gallery' && (
          <GalleryPage 
            handleZipUpload={handleZipUpload} 
            zipImages={zipImages} 
            isProcessingZip={isProcessingZip} 
          />
        )}
        {activeTab === 'contact' && <ContactPage />}
      </main>

      {/* 4. FOOTER */}
      <footer>
        <div className="footer-grid">
          <div>
            <img src={logo} alt="Jillu Curtains" style={{ width: '120px', marginBottom: '10px' }} />
            <p style={{ color: 'var(--text-muted)', fontSize: '0.85rem' }}>
              Window Dressing Solutions. High-end luxury drapes and blinds.
            </p>
          </div>
          <div>
            <h4 className="gold-text">Quick Links</h4>
            <ul style={{ listStyle: 'none', lineHeight: '2' }}>
              {['home', 'about', 'services', 'gallery', 'contact'].map((item) => (
                <li key={item} style={{ cursor: 'pointer', color: '#ccc' }} onClick={() => setActiveTab(item)}>
                  {item.charAt(0).toUpperCase() + item.slice(1)}
                </li>
              ))}
            </ul>
          </div>
          <div>
            <h4 className="gold-text">Contact</h4>
            <p style={{ color: 'var(--text-muted)', fontSize: '0.85rem', lineHeight: '1.8' }}>
              📞 Call: +1 (800) 555-GOLD<br />
              ✉️ Email: contact@jillucurtains.com
            </p>
          </div>
        </div>
      </footer>
    </div>
  );
}

const HomePage = ({ setActiveTab }) => (
  <section className="section" style={{ textAlign: 'center', padding: '100px 20px' }}>
    <h1 className="gold-text" style={{ fontSize: '3rem', marginBottom: '10px' }}>Jillu Curtains</h1>
    <h3 style={{ color: '#aaa', fontWeight: 'normal', marginBottom: '30px' }}>Window Dressing Solutions</h3>
    <button className="btn-gold" onClick={() => setActiveTab('gallery')}>Upload & Extract Catalog Archive</button>
  </section>
);

const AboutPage = () => (
  <section className="section">
    <h1 className="gold-text">About Jillu Curtains</h1>
    <p style={{ color: '#aaa', marginTop: '15px' }}>Custom luxury drapery, blinds, and interior window solutions.</p>
  </section>
);

const ServicesPage = () => (
  <section className="section">
    <h1 className="gold-text">Our Services</h1>
    <p style={{ color: '#aaa', marginTop: '15px' }}>In-Home Consultation, Custom Stitching, Motorized Blinds, and Fitting.</p>
  </section>
);

const GalleryPage = ({ handleZipUpload, zipImages, isProcessingZip }) => (
  <section className="section">
    <h1 className="gold-text">Jillu Curtains ZIP Extractor</h1>
    <p style={{ color: '#aaa', margin: '10px 0 20px' }}>Select your own <code>.zip</code> archive containing images to unpack your custom portfolio.</p>

    <div className="card" style={{ textAlign: 'center', padding: '30px' }}>
      <input 
        type="file" 
        accept=".zip" 
        onChange={handleZipUpload} 
        style={{ color: '#fff', margin: '10px auto', display: 'block' }} 
      />
      {isProcessingZip && <p style={{ color: 'var(--gold-primary)', marginTop: '15px' }}>Unpacking your archive...</p>}
    </div>

    {zipImages.length > 0 && (
      <div style={{ marginTop: '30px' }}>
        <h3 className="gold-text" style={{ marginBottom: '15px' }}>Extracted Portfolio Images ({zipImages.length})</h3>
        <div className="grid-3">
          {zipImages.map((img, idx) => (
            <div key={idx} className="card" style={{ padding: '10px' }}>
              <img src={img.url} alt={img.name} style={{ width: '100%', height: '200px', objectFit: 'cover', borderRadius: '4px' }} />
              <p style={{ color: '#888', fontSize: '0.8rem', marginTop: '8px', wordBreak: 'break-all' }}>{img.name}</p>
            </div>
          ))}
        </div>
      </div>
    )}
  </section>
);

const ContactPage = () => (
  <section className="section">
    <h1 className="gold-text">Contact Jillu Curtains</h1>
    <p style={{ color: '#aaa', marginTop: '15px' }}>Get in touch for a custom window measurement session.</p>
  </section>
);

export default App;
